DROP TABLE IF EXISTS `sys_article`;
CREATE TABLE `sys_article` (
  `id` varchar(36) COLLATE utf8_bin NOT NULL COMMENT '主键',
  `name` varchar(255) COLLATE utf8_bin DEFAULT NULL COMMENT '名称',
  `type` varchar(255) COLLATE utf8_bin DEFAULT NULL COMMENT '类型',
  `img` varchar(512) COLLATE utf8_bin DEFAULT NULL COMMENT '图片（本地路径或外链封面）',
  `content` longtext COLLATE utf8_bin COMMENT '内容',
  `source_url` varchar(768) COLLATE utf8_bin DEFAULT NULL COMMENT '外链原文',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin;

