DROP TABLE IF EXISTS `sys_slideshow`;
CREATE TABLE `sys_slideshow` (
  `id` varchar(36) COLLATE utf8_bin NOT NULL COMMENT '主键',
  `item_id` varchar(36) COLLATE utf8_bin DEFAULT NULL COMMENT '商品id',
  `img` varchar(255) COLLATE utf8_bin DEFAULT NULL COMMENT '图片',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin;

