-- ----------------------------
-- Table structure for sys_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user` (
  `id` varchar(30) NOT NULL COMMENT '主键ID',
  `username` varchar(50) NOT NULL COMMENT '账户名称',
  `salt` varchar(20) DEFAULT NULL COMMENT '加密盐值',
  `password` varchar(225) NOT NULL COMMENT '用户密码密文',
  `phone` varchar(20) DEFAULT NULL COMMENT '手机号码',
  `real_name` varchar(60) DEFAULT NULL COMMENT '真实名称',
  `nick_name` varchar(60) DEFAULT NULL COMMENT '昵称',
  `email` varchar(50) DEFAULT NULL COMMENT '邮箱(唯一)',
  `status` varchar(36) DEFAULT '1' COMMENT '账户状态(1.正常 2.锁定 )',
  `sex` varchar(36) DEFAULT '1' COMMENT '性别(1.男 2.女)',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `roleId` varchar(30) DEFAULT NULL COMMENT '用户角色id',
  `img_url` varchar(255) DEFAULT NULL COMMENT '用户头像',
  `community` varchar(255) DEFAULT NULL,
  `age` varchar(255) DEFAULT NULL COMMENT '年龄',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_username` (`username`) USING BTREE COMMENT '唯一索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

